async (params, browser) => {
  // Open WhatsApp Web
  await browser.open('https://web.whatsapp.com')

  // Wait for WhatsApp to load
  await browser.waitForSelector('div[contenteditable=\'true\'][data-tab=\'3\'], div#side', 30000)

  // Let app fully render
  await browser.wait(3000)

  // Search and extract results
  const result = await browser.evaluate(`const searchBox = document.querySelector('div[contenteditable="true"][data-tab="3"]'); if (!searchBox) throw new Error('Search box not found'); searchBox.focus(); searchBox.textContent = ''; document.execCommand('insertText', false, params.query); searchBox.dispatchEvent(new Event('input', { bubbles: true })); await new Promise(r => setTimeout(r, 2500)); const results = []; const chatItems = document.querySelectorAll('#pane-side [data-testid="list-item"], #pane-side [data-testid="cell-frame-container"], div[data-testid="chatlist"] div[tabindex]'); for (let i = 0; i < Math.min(chatItems.length, 15); i++) { const item = chatItems[i]; const nameEl = item.querySelector('span[title], [data-testid="cell-frame-title"] span'); const msgEl = item.querySelector('span[data-testid="last-msg-status"], .matched-text, span.selectable-text'); const timeEl = item.querySelector('div._amk6, [data-testid="cell-frame-secondary"]'); results.push({ name: nameEl?.getAttribute('title') || nameEl?.textContent?.trim() || '', last_message: msgEl?.textContent?.trim()?.substring(0, 150) || '', time: timeEl?.textContent?.trim() || '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return result
}
